class Solution:
    def findingUsersActiveMinutes(self, logs, k):
        """
        :type logs: List[List[int]]
        :type k: int
        :rtype: List[int]
        """
        user_minutes = defaultdict(set)

        for user_id, time in logs:
            user_minutes[user_id].add(time)

        answer = [0] * k

        for uam in user_minutes.values():
            if len(uam) <= k:
                answer[len(uam) - 1] += 1

        return answer
